api = {
    1: {"items": ["a"], "next": 2},
    2: {"items": ["b", "c"], "next": None},
}

def collect_all(api):
    page, out = 1, []
    while page is not None:
        body = api[page]
        out.extend(body["items"])
        page = body["next"]
    return out

print(collect_all(api))
